import { useEffect, useRef } from 'react'
import { useLocation } from 'react-router-dom'
import { posthog, posthogEnabled } from '@/lib/posthog'
import { useAuthStore } from '@/stores/authStore'

/**
 * Captures a $pageview event whenever the route changes.
 * No-op when PostHog is disabled (missing VITE_POSTHOG_KEY).
 */
export function usePostHogPageview(): void {
  const { pathname } = useLocation()

  useEffect(() => {
    if (!posthogEnabled) return
    posthog.capture('$pageview', { $current_url: pathname })
  }, [pathname])
}

/**
 * Identifies / resets the PostHog user when authentication state changes.
 * Calls posthog.identify() on login, posthog.reset() on logout.
 * No-op when PostHog is disabled.
 */
export function usePostHogIdentify(): void {
  const user = useAuthStore((s) => s.user)
  const prevIdRef = useRef<string | undefined>(undefined)

  useEffect(() => {
    if (!posthogEnabled) return

    const id = user?.id
    if (id && id !== prevIdRef.current) {
      posthog.identify(id, { email: user?.email })
      prevIdRef.current = id
    } else if (!id && prevIdRef.current) {
      posthog.reset()
      prevIdRef.current = undefined
    }
  }, [user])
}

